/* CustScheduleMapper.insertMsgQueue */
INSERT INTO MSG_QUEUE (
	MSEQ
	, MSG_TYPE
	, DSTADDR
	, CALLBACK
	, STAT
	, TEXT_TYPE
	, TEXT
	, EXPIRETIME
	, REQUEST_TIME
	, OPT_ID
) VALUES (
	SMS_SEQ.NEXTVAL
	, #{MSG_TYPE}
	, #{CTN}
	, #{CALLBACK}
	, 0
	, #{TEXT_TYPE}
	, #{MSG}
	, 86400


	, TO_DATE(TO_CHAR(SYSDATE, 'YYYYMMDD') || #{REQ_SEND_TM} || '00', 'YYYYMMDDHH24MISS')


	, SYSDATE


	, 'MSP'
)
